// 1. Get the true/false state from the "All" switch
let state = msg.payload;

// 2. Save this state to the flow context so the individual logic knows about it
flow.set('atrium1', state);
flow.set('atrium2', state);
flow.set('atrium3', state);

// 3. Send the payload to all 3 outputs to update the individual UI switches
return [
    { payload: state }, // Goes to Atrium 1
    { payload: state }, // Goes to Atrium 2
    { payload: state }  // Goes to Atrium 3
];

// 1. msg.topic tells us which switch triggered this (atrium1, atrium2, or atrium3)
// Update that specific atrium's state in the flow context
flow.set(msg.topic, msg.payload);

// 2. Read the current state of all 3 atriums
let a1 = flow.get('atrium1') || false;
let a2 = flow.get('atrium2') || false;
let a3 = flow.get('atrium3') || false;

// 3. Check if ALL of them are true
let allChecked = (a1 && a2 && a3);

// 4. Send this result to the "All Atriums" switch to update its UI
return { payload: allChecked };

let inputStr = msg.payload.trim();
let spaceIndex = inputStr.indexOf(" ");

if (spaceIndex !== -1) {
    // A space was found! Split into Address and Argument
    msg.topic = inputStr.substring(0, spaceIndex); // Gets "/cmd"

    let argStr = inputStr.substring(spaceIndex + 1).trim(); // Gets '"Off Timecode 2"'

    // Remove literal quotes if you typed them, the OSC node doesn't need them
    if (argStr.startsWith('"') && argStr.endsWith('"')) {
        argStr = argStr.slice(1, -1);
    }

    msg.payload = argStr; // Set the argument
} else {
    // No spaces found (like "/cue/1/start"). The whole thing is the address.
    msg.topic = inputStr;
    msg.payload = "";
}

// Grab the port we saved from the button group (default to 53000)
msg.port = flow.get("oscPort") || 53000; 

return msg;

// name=Status Snapshot Handler (stable)
const KEY = "exit10_status_snapshot";

// UI request: reply with snapshot only
if (msg?.payload?.ui === "getSnapshot") {
    const snap = global.get(KEY) || {};
    return { payload: snap, _from: "snapshotReply" };
}

// Normal update: merge into snapshot and forward
if (msg.payload && typeof msg.payload === "object") {
    const snap = global.get(KEY) || {};

    // single {id, state, ...}
    if (msg.payload.id) {
        const { id, ...rest } = msg.payload;
        if (!snap[id] || typeof snap[id] !== "object") snap[id] = {};
        Object.assign(snap[id], rest);
    } else {
        // bulk { id1: "connected", id2: {state, meta}, ... }
        for (const [id, val] of Object.entries(msg.payload)) {
            if (val && typeof val === "object") {
                if (!snap[id] || typeof snap[id] !== "object") snap[id] = {};
                Object.assign(snap[id], val);
            } else if (typeof val === "string") {
                if (!snap[id] || typeof snap[id] !== "object") snap[id] = {};
                snap[id].state = val;
            }
        }
    }

    global.set(KEY, snap);
    return msg; // forward to UI
}

return null;

'use strict';
var fs   = require('fs');
var path = require('path');
var userDir = (typeof RED !== 'undefined' && RED.settings && RED.settings.userDir)
    ? RED.settings.userDir : process.cwd();

function findConfigPath(dir) {
    var tried = [];
    try {
        var projDir = path.join(dir, 'projects');
        var projects = fs.readdirSync(projDir);
        for (var i = 0; i < projects.length; i++) {
            var p = path.join(projDir, projects[i], 'node-red', 'config', 'ma-config.json');
            tried.push(p);
            if (fs.existsSync(p)) return { path: p, tried: tried };
        }
    } catch(e) {
        if (e.code !== 'ENOENT' && e.code !== 'ENOTDIR') {
            node.warn('[MA Init] projects dir scan: ' + e.message);
        }
    }
    var p2 = path.join(dir, 'node-red', 'config', 'ma-config.json');
    tried.push(p2);
    if (fs.existsSync(p2)) return { path: p2, tried: tried };
    var p3 = path.join(dir, 'config', 'ma-config.json');
    tried.push(p3);
    if (fs.existsSync(p3)) return { path: p3, tried: tried };
    return { path: null, tried: tried };
}

var found = findConfigPath(userDir);
if (!found.path) {
    node.error('[MA Init] ma-config.json not found. Tried: ' + found.tried.join(', '));
    return { topic: 'ma/init/error', payload: { error: 'ma-config.json not found', attempted: found.tried } };
}
var configPath = found.path;
var config;
try {
    config = JSON.parse(fs.readFileSync(configPath, 'utf8'));
} catch (err) {
    node.error('[MA Init] Failed to read config from ' + configPath + ': ' + err.message);
    return { topic: 'ma/init/error', payload: { error: err.message, path: configPath } };
}
global.set('ma_config', config);
if (global.get('ma_owner') === undefined) {
    global.set('ma_owner', null);
    global.set('ma_owner_setBy', 'ma-init');
}
if (!global.get('ma_zones')) global.set('ma_zones', { a1: false, a2: false, a3: false, ls: false });
if (global.get('ma_exec_cue') === undefined) global.set('ma_exec_cue', 1);
if (global.get('ma_seq_id')   === undefined) global.set('ma_seq_id',   1);
if (global.get('ma_seq_cue')  === undefined) global.set('ma_seq_cue',  1);
var owner = global.get('ma_owner');
var setBy = global.get('ma_owner_setBy');
var zones = Object.keys((config.zoneExecutor || {})).join(', ');
node.log('[MA Init] Config loaded from ' + configPath + '. Zones: ' + zones + '. Owner: ' + owner);
return { topic: 'ma/init', payload: { config: config, owner: owner, setBy: setBy, message: 'MA config loaded. Zones: ' + zones + '. Owner: ' + owner } };

'use strict';
var owner = (msg.payload === '' || msg.payload == null) ? null : msg.payload;
msg.payload = { action: 'setOwner', owner: owner, setBy: 'nodered-ui' };
return msg;

'use strict';
// Outputs: [sw-all, sw-a1, sw-a2, sw-a3, sw-ls]
// passthru:false on each switch prevents incoming state msgs from re-firing
// output, so updating switches here never creates feedback loops.
var topic = msg.topic;
var val = !!msg.payload;
var zones = global.get('ma_zones') || { a1: false, a2: false, a3: false, ls: false };
if (topic === 'zone/all') {
    zones.a1 = val;
    zones.a2 = val;
    zones.a3 = val;
    zones.ls = val;
} else {
    var zone = topic.split('/')[1];
    if (zone && Object.prototype.hasOwnProperty.call(zones, zone)) {
        zones[zone] = val;
    }
}
global.set('ma_zones', zones);
var allOn = zones.a1 && zones.a2 && zones.a3 && zones.ls;
return [
    [{ payload: allOn,    topic: 'zone/all' }],
    [{ payload: zones.a1, topic: 'zone/a1'  }],
    [{ payload: zones.a2, topic: 'zone/a2'  }],
    [{ payload: zones.a3, topic: 'zone/a3'  }],
    [{ payload: zones.ls, topic: 'zone/ls'  }]
];

'use strict';
var zones = global.get('ma_zones') || { a1: false, a2: false, a3: false, ls: false };
var selectedZones = ['a1', 'a2', 'a3', 'ls'].filter(function(z) { return zones[z]; });
if (selectedZones.length === 0) {
    node.warn('[MA] goExecutorCue — no zones selected');
    return null;
}
var cue = global.get('ma_exec_cue');
if (cue == null) cue = 1;
msg.payload = { action: 'goExecutorCue', zones: selectedZones, cue: cue };
return msg;

'use strict';
var seq = global.get('ma_seq_id');
if (seq == null) seq = 1;
var cue = global.get('ma_seq_cue');
if (cue == null) cue = 1;
msg.payload = { action: 'goSequenceCue', sequence: seq, cue: cue };
return msg;

'use strict';
var input = msg.payload || {};
var action = input.action;
var rawOwner = global.get('ma_owner');
var currentOwner = (rawOwner !== undefined) ? rawOwner : null;
var maConfig = global.get('ma_config') || {};

function sendCmd(cmdStr) {
    node.send([{ topic: '/cmd', payload: cmdStr }, null]);
}
function sendStatus(topic, payload) {
    node.send([null, { topic: topic, payload: payload }]);
}

if (action === 'setOwner') {
    var newOwner = (input.owner != null && input.owner !== '') ? input.owner : null;
    global.set('ma_owner', newOwner);
    global.set('ma_owner_setBy', input.setBy || 'nodered-ui');
    sendStatus('ma/owner', { action: 'setOwner', owner: newOwner, setBy: global.get('ma_owner_setBy') });
    return null;
}

if (action === 'goExecutorCue') {
    if (currentOwner !== null && currentOwner !== 'nodered') {
        sendStatus('ma/goExecutorCue/blocked', { action: action, requiredOwner: 'nodered', currentOwner: currentOwner });
        return null;
    }
    var zoneExecutor = maConfig.zoneExecutor;
    if (!zoneExecutor) {
        sendStatus('ma/error', { error: 'global.ma_config.zoneExecutor not set — run init first' });
        return null;
    }
    var zones = Array.isArray(input.zones) ? input.zones : [];
    if (zones.length === 0) {
        sendStatus('ma/error', { error: "'zones' must be a non-empty array for goExecutorCue" });
        return null;
    }
    if (input.cue == null) {
        sendStatus('ma/error', { error: "'cue' is required for goExecutorCue" });
        return null;
    }
    var msgs = zones.map(function (zone) {
        var exec = (zoneExecutor[zone] !== undefined) ? String(zoneExecutor[zone]) : String(zone);
        return { topic: '/cmd', payload: 'Go+ Executor ' + exec + ' Cue ' + input.cue };
    });
    node.send([msgs, null]);
    return null;
}

if (action === 'goSequenceCue') {
    if (currentOwner !== null && currentOwner !== 'watchout') {
        sendStatus('ma/goSequenceCue/blocked', { action: action, requiredOwner: 'watchout', currentOwner: currentOwner });
        return null;
    }
    if (input.sequence == null) {
        sendStatus('ma/error', { error: "'sequence' is required for goSequenceCue" });
        return null;
    }
    if (input.cue == null) {
        sendStatus('ma/error', { error: "'cue' is required for goSequenceCue" });
        return null;
    }
    sendCmd('Go+ Sequence ' + input.sequence + ' Cue ' + input.cue);
    return null;
}

sendStatus('ma/error', { error: "Unknown action: '" + action + "'" });
return null;

// Set path to watchout-config.json (edit this path if needed)
msg.filename = msg.payload || '/data/projects/XYZ-Exit10/node-red/config/watchout-config.json';
return msg;

// Parse watchout-config.json
let cfg = {};
try {
    cfg = JSON.parse(msg.payload);
} catch(e) {
    node.warn('[Watchout] watchout-config.json parse error, using defaults: ' + e.message);
}
cfg.host        = cfg.host        || 'localhost';
cfg.port        = cfg.port        || 3019;
cfg.mappingFile = cfg.mappingFile || '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
flow.set('watchout_config', cfg);
node.status({ fill: 'green', shape: 'dot', text: 'Config: ' + cfg.host + ':' + cfg.port });
// Feed filename forward to read mapping file
msg.filename = cfg.mappingFile;
return msg;

// Config file missing — create defaults
const defaultCfg = {
    host: 'localhost',
    port: 3019,
    mappingFile: '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json'
};
flow.set('watchout_config', defaultCfg);
node.warn('[Watchout] watchout-config.json not found — writing defaults');
msg.filename = '/config/watchout-config.json';
msg.payload  = JSON.stringify(defaultCfg, null, 2);
return msg;

// After writing default config, continue to mapping read
const cfg = flow.get('watchout_config') || {};
msg.filename = cfg.mappingFile || '/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
return msg;

// Parse timeline-mapping.json
let mapping = {};
try {
    const raw = JSON.parse(msg.payload);
    mapping = raw.mapping || raw || {};
} catch(e) {
    node.warn('[Watchout] timeline-mapping.json parse error, starting empty: ' + e.message);
}
flow.set('watchout_mapping', mapping);
flow.set('watchout_pending', null);
const count = Object.keys(mapping).length;
node.status({ fill: 'green', shape: 'dot', text: 'Mapping loaded: ' + count + ' timelines' });
return null;

// Mapping file missing — start with empty mapping
flow.set('watchout_mapping', {});
flow.set('watchout_pending', null);
node.warn('[Watchout] timeline-mapping.json not found — starting with empty mapping');
return null;

// Build the HTTP GET request for /v0/timelines
const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
msg.method  = 'GET';
msg.url     = 'http://' + host + ':' + port + '/v0/timelines';
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Prepare mapping JSON for file write
const pending = flow.get('watchout_pending');
if (!pending) {
    node.send({ payload: { status: 'nothing_pending' }, topic: 'watchout/confirm' });
    return null;
}

// Update flow context immediately
flow.set('watchout_mapping', pending);
flow.set('watchout_pending', null);

// Prepare file write
const cfg = flow.get('watchout_config') || {};
msg.filename = cfg.mappingFile || '/data/projects/XYZ-Exit10/node-red/data/timeline-mapping.json';
msg.payload  = JSON.stringify({ mapping: pending, lastSaved: new Date().toISOString() }, null, 2);
msg._pendingMapping = pending;
msg._savedAt = new Date().toISOString();
return msg;

// Confirm & Save completed
const mapping = msg._pendingMapping || flow.get('watchout_mapping') || {};
node.status({ fill: 'green', shape: 'dot', text: 'Saved: ' + Object.keys(mapping).length + ' timelines' });
node.send({
    payload: {
        status:  'saved',
        mapping: mapping,
        savedAt: msg._savedAt || new Date().toISOString()
    },
    topic: 'watchout/confirm'
});
return null;

// Cancel pending discovery
flow.set('watchout_pending', null);
node.send({ payload: { status: 'cancelled' }, topic: 'watchout/cancel' });
return null;

// Validate input and build HTTP request for timeline control.
// Output 1: valid command  → HTTP Request node
// Output 2: unknown command → HTTP Response (error)

const cfg     = flow.get('watchout_config') || {};
const host    = cfg.host || 'localhost';
const port    = cfg.port || 3019;
const baseUrl = 'http://' + host + ':' + port;

const input   = msg.payload || {};
const command = input.command;
const mapping = flow.get('watchout_mapping') || {};

function resolveTimelineId(contentId) {
    return (contentId in mapping) ? mapping[contentId] : String(contentId);
}

msg._command = command;
msg.headers  = { 'Content-Type': 'application/json' };

switch (command) {
    case 'start':
    case 'stop':
    case 'pause': {
        const timelineId   = resolveTimelineId(input.contentId);
        msg._timelineId    = timelineId;
        msg.method         = 'POST';
        const action       = (command === 'start') ? 'play' : command;
        msg.url            = baseUrl + '/v0/timelines/' + timelineId + '/' + action;
        msg.payload        = null;
        return [msg, null];
    }
    case 'setVar': {
        msg.method  = 'PUT';
        msg.url     = baseUrl + '/v0/vars/' + encodeURIComponent(input.varName);
        msg.payload = { value: input.varValue };
        return [msg, null];
    }
    case 'getState': {
        msg.method  = 'GET';
        msg.url     = baseUrl + '/v0/state';
        msg.payload = null;
        return [msg, null];
    }
    default: {
        msg.statusCode = 400;
        msg.payload    = JSON.stringify({ success: false, error: 'Unknown command: ' + command });
        return [null, msg];
    }
}

// Build the SSE endpoint URL from flow config and trigger the SSE client
const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'host.docker.internal';
const port = cfg.port || 3019;
msg.url     = 'http://' + host + ':' + port + '/v1/sse';
msg.headers = { 'Accept': 'text/event-stream', 'Cache-Control': 'no-cache' };
flow.set('watchout_sse_status', 'connecting');
return msg;

// Only poll Watchout state when SSE is not connected (fallback mode)
if (flow.get('watchout_sse_status') === 'connected') {
    return null;
}

const cfg  = flow.get('watchout_config') || {};
const host = cfg.host || 'localhost';
const port = cfg.port || 3019;
msg.method  = 'GET';
msg.url     = 'http://' + host + ':' + port + '/v0/state';
msg.headers = { 'Content-Type': 'application/json' };
return msg;

// Parse GET /v0/timelines response and build diff

if (msg.statusCode !== 200) {
    msg.payload = { status: 'error', error: 'Watchout returned HTTP ' + (msg.statusCode || 'unknown') };
    return msg;
}

function parseTimelineName(name) {
    if (!name || name.startsWith('_')) return null;
    return name.trim().toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');
}

function compareMapping(oldMap, newMap) {
    const oldKeys = Object.keys(oldMap);
    const newKeys = Object.keys(newMap);
    return {
        removed:   oldKeys.filter(k => !(k in newMap)),
        added:     newKeys.filter(k => !(k in oldMap)),
        unchanged: oldKeys.filter(k => (k in newMap) && oldMap[k] === newMap[k]),
        changed:   oldKeys.filter(k => (k in newMap) && oldMap[k] !== newMap[k]),
    };
}

function formatDiff(diff) {
    const lines = [];
    diff.removed.forEach(n   => lines.push("REMOVED  : Timeline '" + n + "' no longer exists"));
    diff.added.forEach(n     => lines.push("ADDED    : New timeline '" + n + "' discovered"));
    diff.changed.forEach(n   => lines.push("CHANGED  : Timeline '" + n + "' ID has changed"));
    diff.unchanged.forEach(n   => lines.push("OK       : '" + n + "'"));
    return lines;
}

const timelines = Array.isArray(msg.payload) ? msg.payload : [];

const newMapping = {};
timelines.forEach(tl => {
    const contentId = parseTimelineName(tl.name);
    if (contentId) newMapping[contentId] = String(tl.id);
});

const storedMapping = flow.get('watchout_mapping') || {};
const diff     = compareMapping(storedMapping, newMapping);
const diffLines = formatDiff(diff);

flow.set('watchout_pending', newMapping);

const count = Object.keys(newMapping).length;
node.status({ fill: 'green', shape: 'dot', text: 'Discovered: ' + count + ' timelines' });

msg.payload = { status: 'discovered', count, diffLines, newMapping, diff };
return msg;

// Normalize the Watchout API response into a uniform JSON object
const command    = msg._command;
const timelineId = msg._timelineId;
const statusCode = msg.statusCode || 200;

msg.payload    = JSON.stringify({
    success:    statusCode < 300,
    command:    command,
    timelineId: timelineId,
    statusCode: statusCode,
    body:       msg.payload
});
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json' };
return msg;

// Process an incoming SSE event from the Watchout SSE client node.
// msg.payload = event data (auto-parsed JSON if possible)
// msg.event   = event type string

const wasConnected = flow.get('watchout_sse_status') === 'connected';

const event = {
    type: msg.event || 'message',
    data: msg.payload
};

flow.set('watchout_state',      event.data || event);
flow.set('watchout_sse_status', 'connected');

// Output 1: state event for Live State UI
const stateMsg  = { payload: event, topic: 'watchout/state' };

// Output 2: SSE status update (only send once on initial connect)
const statusMsg = wasConnected ? null
    : { payload: { status: 'sse_connected' } };

node.send([stateMsg, statusMsg]);
return null;

// Handle SSE connection errors / disconnects
flow.set('watchout_sse_status', 'error');
const errMsg = (msg.error && msg.error.message) ? msg.error.message : String(msg.error || 'SSE error');
node.send({ payload: { status: 'sse_error', message: errMsg } });
return null;

// Handle the GET /v0/state poll response
const statusCode = msg.statusCode || 200;
if (statusCode !== 200) {
    node.warn('[Watchout Poll] HTTP ' + statusCode);
    return null;
}

const state = msg.payload;
flow.set('watchout_state', state);

node.send({ payload: { type: 'poll', data: state }, topic: 'watchout/state' });
return null;

// Input can be:
// - msg.watchout_sse_status
// - msg.payload.status
// - or read from flow context
const raw =
  msg.watchout_sse_status ||
  msg.payload?.watchout_sse_status ||
  flow.get("watchout_sse_status");

let state = "disconnected";
if (raw === "connected") state = "connected";
else if (raw === "disconnected") state = "disconnected";
else if (raw === "error") state = "error";
else if (raw === "connecting") state = "connecting"; // if you add this in your flow

msg.payload = {
  state,
  label: "Watchout",
  layout: "row",
};

return msg;
